    },
    primeira_mensagem_enviada_at_candidate: (!skip && canSendNow) ? (item.primeira_mensagem_enviada_at || item.primeiro_contato_at || nowIso) : null,
  },
}];

const claim = $('Claim dispatch lease').first().json || {};
const d = new Date();
d.setHours(d.getHours() + 24);
return [{ json: { session_id: $json.session_id, proximo_envio_at: d.toISOString(), touchpoint_id: $json.touchpoint_id, skipReason: $json.skipReason, _dispatch_execution_id: claim._dispatch_execution_id || '' } }];

/**
 * Code node "D1 WA variacao" — SDR Outbound (n8n).
 * Coloque APÓS "Pode enviar WA?" (ramo true) e ANTES de "Gerar Msg".
 * Depende de: Supabase migration 008 (rpc/next_d1_wa_variacao).
 */

return await (async function () {
  const V1 = `D1_WA (Abertura) — VARIAÇÃO 1
Se apresente (evite "olá"; prefira "oi, tudo bem?" ou bom dia/boa tarde conforme o horário) e confirme se fala com quem decide pelo estabelecimento. Diga que o restaurante chamou atenção num estudo de mercado da região e que por isso estamos oferecendo algo gratuito para ele. Se tiver rapport, use como gancho. Crie exclusividade. NUNCA cite valor financeiro. Termine com pergunta de baixa fricção.
Mantenha curto e chamativo; o objetivo é só despertar curiosidade.`;

  const V2 = `D1_WA (Abertura) — VARIAÇÃO 2
Abra com tom leve (oi/tudo bem ou bom dia/boa tarde) e confirme o contato certo. Diga que estamos fechando um recorte de desempenho dos negócios do bairro/região e que o restaurante entrou no radar por um motivo específico (use rating, perfil ou dado do radar com cuidado, sem inventar). Ofereça um material gratuito ligado a esse recorte, sem citar sistema ou produto. Crie exclusividade. NUNCA cite valor financeiro. Feche com pergunta simples.
Máximo 3 linhas; uma ideia por mensagem.`;

  const V3 = `D1_WA (Abertura) — VARIAÇÃO 3
Comece naturalmente (evite "olá") e valide se está falando com quem manda no salão. Mencione que fazemos um mapeamento rápido de operações na região e que o nome do restaurante apareceu como caso interessante para acompanhar (use apenas dados que já estão no contexto). Convide a receber um resumo gratuito desse recorte, sem mencionar software ou marca de ferramenta. NUNCA cite valor financeiro. Uma pergunta curta no fim.
Seja direto; curiosidade antes de qualquer detalhe.`;

  const BLOQUES = { 1: V1, 2: V2, 3: V3 };

  const prep = $('Preparar touchpoint').first().json;
  const tp = prep.touchpoint_id;

  if (tp !== 'D1_WA') {
    return [
      {
        json: {
          d1_wa_variacao: null,
          d1_wa_copy_block: '',
          abertura_variacao: null,
        },
      },
    ];
  }

  let v = 1;
  try {
    const cred = await this.getCredentials('supabaseApi');
    const host = String(cred.host || '').replace(/\/$/, '');
    const key = cred.serviceRole;
    const raw = await this.helpers.httpRequest({
      method: 'POST',
      url: `${host}/rest/v1/rpc/next_d1_wa_variacao`,
      headers: {
        apikey: key,
        Authorization: `Bearer ${key}`,
        'Content-Type': 'application/json',
      },
      body: '{}',
      json: true,
    });
    if (typeof raw === 'number') v = raw;
    else if (raw && raw.next_d1_wa_variacao != null) v = raw.next_d1_wa_variacao;
    else v = parseInt(raw, 10) || 1;
    v = Math.max(1, Math.min(3, parseInt(v, 10) || 1));
  } catch (e) {
    v = (Date.now() % 3) + 1;
  }

  return [
    {
      json: {
        d1_wa_variacao: v,
        d1_wa_copy_block: BLOQUES[v] || BLOQUES[1],
        abertura_variacao: v,
      },
    },
  ];
}).call(this);

/**
 * Code node "UAZAPI — payload falha" — após IF "Error?" (ramo TRUE = falha envio, ex. HTTP 500).
 * Entrada: saída do nó "UAZAPI — enviar texto" (item com .error em falha).
 */
const prep = $('Preparar touchpoint').first().json;
const msg = $('Gerar Msg').first().json;
const d1 = $('D1 WA variacao').first().json;
const raw = $input.first().json || {};
const err = raw.error || {};
const status = Number(
  err.statusCode ?? err.status ?? err.response?.status ?? raw.statusCode ?? NaN
);
const errMsg =
  (typeof err.message === 'string' && err.message) ||
  (typeof err.error === 'string' && err.error) ||
  '';
let body = err.response?.body ?? err.response?.data ?? err.cause;
if (body && typeof body !== 'string') {
  try {
    body = JSON.stringify(body);
  } catch (e) {
    body = String(body);
  }
}
const mensagemTexto = msg && msg.output != null ? String(msg.output) : '';

const metadata = {
  uazapi_http_status: Number.isFinite(status) ? status : null,
  uazapi_error_message: errMsg.slice(0, 4000),
  uazapi_error_body: body ? String(body).slice(0, 8000) : '',
  falha_motivo:
    status === 500 ? 'erro_provedor_ou_numero_invalido' : 'falha_http_uazapi',
};

return [
  {
    json: {
      session_id: prep.session_id,
      touchpoint_id: prep.touchpoint_id,
      canal: prep.canal,
      formato: 'texto',
      direcao: 'outbound',
      mensagem_texto: mensagemTexto,
      resultado: 'falha_envio',
      metadata,
      abertura_variacao: d1 && d1.abertura_variacao != null ? d1.abertura_variacao : null,
      proximo_envio_at_retry: (() => {
        const t = new Date();
        t.setHours(t.getHours() + 24);
        return t.toISOString();
      })(),
    },
  },
];

/**
 * Code node "Claim dispatch lease" — SDR Outbound (n8n).
 * Coloque APÓS "Um lead por vez" (saída do lote) e ANTES de "Preparar touchpoint".
 * Depende de: supabase/migrations/015_outbound_dispatch_lease.sql (RPC try_claim_outbound_session).
 *
 * Saída: repete os campos da sessão + _dispatch_claimed (boolean) + _dispatch_execution_id (string).
 */

return await (async function () {
  const row = $input.first().json;
  const sessionId = row.id;
  if (!sessionId) {
    return [
      {
        json: {
          ...row,
          _dispatch_claimed: false,
          _dispatch_skip_reason: 'no_session_id',
          _dispatch_execution_id: '',
        },
      },
    ];
  }

  const cred = await this.getCredentials('supabaseApi');
  const host = String(cred.host || '').replace(/\/$/, '');
  const key = cred.serviceRole;
  const executionId =
    typeof $execution !== 'undefined' && $execution.id != null
      ? String($execution.id)
      : `no-exec-${Date.now()}`;

  let claimed = false;
  try {
    const raw = await this.helpers.httpRequest({
      method: 'POST',
      url: `${host}/rest/v1/rpc/try_claim_outbound_session`,
      headers: {
        apikey: key,
        Authorization: `Bearer ${key}`,
        'Content-Type': 'application/json',
      },
      body: {
        p_session_id: sessionId,
        p_execution_id: executionId,
        p_ttl_seconds: 240,
      },
      json: true,
    });
    if (raw === true || raw === 'true') claimed = true;
    else if (typeof raw === 'boolean') claimed = raw;
  } catch (e) {
    claimed = false;
  }

  return [
    {
      json: {
        ...row,
        _dispatch_claimed: claimed,
        _dispatch_execution_id: executionId,
        _dispatch_skip_reason: claimed ? '' : 'lease_busy_or_rpc_error',
      },
    },
  ];
}).call(this);
